const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

const addComment = (taskId, comment) => {
  const task = tasksService.getTask(taskId);
  if (!task) return null;

  const newComment = { ...comment, id: randomUUID() };
  task.comments.push(newComment);
  return newComment;
};

module.exports = { addComment };

const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const task = req.body;
  if (!task.name) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Task name is required');
  }

  const result = tasksService.addTask(req.projectId, { ...task, status: 'todo' });
  res.status(201).json({ task: result });
});

router.get('/', (req, res) => {
  const { status } = req.query;
  const tasks = tasksService.getTasks(req.projectId);
  if (status) {
    return res.json({ tasks: tasks.filter(t => t.status === status) });
  }
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const result = tasksService.updateTask(taskId, { status });
  if (result === null) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }

  res.json({ task: result });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

const addTask = (projectId, task) => {
  const project = projectsService.getProject(projectId);
  if (!project) return null;

  const newTask = { ...task, id: randomUUID() };
  project.tasks.push(newTask);
  return newTask;
};

const getTasks = (projectId) => {
  const project = projectsService.getProject(projectId);
  if (!project) return [];
  return project.tasks;
};

const updateTask = (taskId, updates) => {
  const project = projectsService.findProjectByTask(taskId);
  if (!project) return null;

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;

  Object.assign(task, updates);
  return task;
};

module.exports = { addTask, getTasks, updateTask };

const express = require('express');
const router = express.Router();
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/:projectId', (req, res) => {
  const project = projectsService.getProject(req.params.projectId);
  if (!project) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.json({ project });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Project name is required');
  }

  const result = projectsService.addProject({ name });
  res.status(201).json({ project: result });
});

module.exports = router;

const { randomUUID } = require('node:crypto');

let projects = [];

const addProject = (project) => {
  const newProject = { ...project, id: randomUUID(), members: [], tasks: [] };
  projects.push(newProject);
  return newProject;
};

const getProject = (projectId) => {
  return projects.find(p => p.id === projectId);
};

const findProjectByTask = (taskId) => {
  return projects.find(p => p.tasks.some(t => t.id === taskId));
};

module.exports = { addProject, getProject, findProjectByTask };

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects/:projectId/members', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, membersRoutes);

app.use('/projects/:projectId/tasks', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
}, tasksRoutes);

app.use('/tasks/:taskId/comments', (req, res, next) => {
  req.taskId = req.params.taskId;
  next();
}, commentsRoutes);

app.use('/projects', projectsRoutes);

module.exports = app;

